import { DAYS } from './scheduler/time.js';
let data = null;
let result = null;
const app = document.querySelector('#app');
const nameOf = (id, kind) => { if (!data)
    return id; const list = kind === 'subject' ? data.subjects : kind === 'teacher' ? data.teachers : kind === 'cohort' ? data.cohorts : data.grades; return list.find(x => x.id === id)?.name ?? id; };
function card(title, value, cls = '') { return `<section class="card ${cls}"><b>${title}</b><strong>${value}</strong></section>`; }
function sourceCell(r) { return `${r.source?.sheetName ?? ''} ${r.source?.sourceCells?.join(', ') ?? (r.source?.sourceRow ? `R${r.source.sourceRow}C${r.source.startColumn}` : '')}`; }
function requirementsPreview() { if (!data)
    return ''; return `<section class="panel"><h2>수업 요구사항</h2>${data.requirements.length === 0 ? '<p class="error">학년별 또는 교사별 수업을 인식하지 못했습니다. 시간표 생성이 비활성화되었습니다.</p>' : ''}<table><thead><tr><th>과목</th><th>참여 그룹</th><th>담당 교사</th><th>주당 총 교시</th><th>주간 횟수</th><th>블록 길이</th><th>원본 시트</th><th>원본 셀</th><th>상태</th><th>문제점</th></tr></thead><tbody>${data.requirements.map(r => `<tr><td>${nameOf(r.subjectId, 'subject')}</td><td>${r.cohortIds.map(c => nameOf(c, 'cohort')).join(', ') || r.gradeIds.map(g => nameOf(g, 'grade')).join(', ')}</td><td>${r.teacherIds.map(t => nameOf(t, 'teacher')).join(', ') || '미지정'}</td><td>${r.totalPeriodsPerWeek}</td><td>${r.meetingsPerWeek}</td><td>${r.meetingLengths.join('+')}</td><td>${r.source?.sheetName ?? ''}</td><td>${sourceCell(r)}</td><td>${r.status ?? 'ready'}</td><td>${r.issues?.join(', ') ?? ''}</td></tr>`).join('')}</tbody></table></section>`; }
function constraintEditor() { if (!data)
    return ''; return `<section class="panel"><h2>제약조건 편집</h2><p>AI 없이도 같은 constraint operations 모델로 고정, 허용/금지, 8교시 전용, 담당 교사와 cohort 변경, 배치 잠금/해제를 저장할 수 있습니다.</p><label>수업 <select id="cr">${data.requirements.map(r => `<option value="${r.id}">${nameOf(r.subjectId, 'subject')} / ${r.cohortIds.map(c => nameOf(c, 'cohort')).join(', ')}</option>`).join('')}</select></label><label>요일 <select id="day">${DAYS.map(d => `<option>${d}</option>`).join('')}</select></label><label>교시 <input id="period" type="number" min="1" max="8" value="1"></label><button id="fix">정확한 요일·교시에 고정</button><button id="after">8교시 전용</button><button id="allow">허용 시간 추가</button><button id="forbid">금지 시간 추가</button><button id="lock">배치 잠금/해제</button></section>`; }
function teacherMappings() { if (!data)
    return ''; const opts = (sel) => `<option value="">-- 선택 --</option>${data.teachers.map(t => `<option value="${t.id}" ${sel === t.id ? 'selected' : ''}>${t.name}</option>`).join('')}`; const homeroom = data.roleMappings?.homeroomByGrade ?? {}; return `<section class="panel"><h2>Teacher mappings / 교사 매핑</h2><p>역할 교사를 실제 교사로 매핑하면 검증과 시간표 생성에 즉시 반영됩니다.</p><h3>각 홈룸 교사</h3><table><tbody>${data.grades.map(g => `<tr><th>${g.name}</th><td><select class="map-home" data-grade="${g.id}">${opts(homeroom[g.id])}</select></td></tr>`).join('')}</tbody></table><h3>학생회 담당 교사</h3><select id="map-council">${opts(data.roleMappings?.studentCouncil)}</select></section>`; }
function ruleReview() { if (!data)
    return ''; const pr = data.diagnostics.parsedRules; const row = (kind, items) => `<h3>${kind}</h3><table><thead><tr><th>원본</th><th>상태</th></tr></thead><tbody>${items.map(x => `<tr><td>${x}</td><td>자동 파싱됨</td></tr>`).join('')}</tbody></table>`; return `<section class="panel"><h2>자동 감지 제약조건</h2>${pr ? `<p>matched ${pr.matched}, ambiguous ${pr.ambiguous}, unmatched ${pr.unmatched}, blocking ${pr.blockingErrors.length}</p>${row('고정수업', pr.fixed)}${row('8교시 고정수업', pr.eighthPeriod)}${row('연속수업', pr.consecutive)}${row('오후 선호 수업', pr.afternoon)}${pr.blockingErrors.map(e => `<p class="error">${e}</p>`).join('')}` : '<p>감지된 규칙 없음</p>'}</section>`; }
function diagnostics() { if (!data)
    return ''; const d = data.diagnostics; return `<section class="panel"><h2>Import 진단</h2><pre>${JSON.stringify({ sheetRanges: d.sheetRanges, headers: d.headers, gradeBlocks: d.gradeBlocks, teacherBlocks: d.teacherBlocks, skippedBlocks: d.skippedBlocks, detectedSubjectCount: d.detectedSubjectCount, detectedRequirementCount: d.detectedRequirementCount, allocationTeacherAliases: [...new Set(d.allocationTeacherAliases)] }, null, 2)}</pre></section>`; }
function tableFor(filter, cell) { const rows = [1, 2, 3, 4, 99, 5, 6, 7, 8]; return `<table class="schedule"><thead><tr><th>교시</th><th>시간</th>${DAYS.map(d => `<th>${d}</th>`).join('')}</tr></thead><tbody>${rows.map(p => `<tr class="${p === 99 ? 'lunch' : ''}"><th>${p === 99 ? '점심' : p}</th><td>${p === 99 ? '11:55-13:05' : p === 8 ? '15:20-16:00' : p < 5 ? ['', '09:00-09:40', '09:45-10:25', '10:30-11:10', '11:15-11:55'][p] : ['', '', '', '', '', '13:05-13:45', '13:50-14:30', '14:35-15:15'][p]}</td>${DAYS.map(d => { const a = result?.assignments.find(x => filter(x) && x.slot === `${d}-${p}`); return `<td>${a ? cell(a) : ''}</td>`; }).join('')}</tr>`).join('')}</tbody></table>`; }
function render() { const issues = data ? uniqueIssues(validateData(data)) : []; const blockers = issues.filter(i => isImportBlockingIssue(i) || ['missing-homeroom-mapping', 'missing-student-council-mapping', 'invalid-teacher-mapping', 'unresolved-teacher-role'].includes(i.code)); const blocking = blockers.length > 0; app.innerHTML = `<header><h1>Chronos Scheduler</h1><p>Excel 기반 교사·학생·학년 시간표 자동 생성 웹앱</p></header><main><section class="panel"><h2>Excel 업로드</h2><div id="drop"><input type="file" id="file" accept=".xlsx"/><p>.xlsx 파일을 드래그하거나 선택하세요.</p></div><button id="load">저장 프로젝트 불러오기</button></section>${data ? `<section class="grid">${card('학생 수', data.students.length)}${card('canonical 학년 수', data.grades.length)}${card('교사 수', data.teachers.length)}${card('과목 수', data.subjects.length)}${card('cohort 수', data.cohorts.length)}${card('CourseRequirement 수', data.requirements.length)}${card('전체 주당 교시', data.requirements.reduce((a, b) => a + b.totalPeriodsPerWeek, 0))}${card('수업 인스턴스', data.requirements.reduce((a, b) => a + b.meetingLengths.length, 0))}${card('오류', issues.filter(i => i.level === 'error').length, 'bad')}${card('경고', issues.filter(i => i.level === 'warning').length, 'warn')}</section><section class="panel"><h2>시트 및 검증</h2><p>${data.sourceSheets.join(', ')}</p><div class="issues">${issues.map(i => `<p class="${i.level}">● [${i.code}] ${i.message}</p>`).join('')}</div></section><section class="panel"><h2>Import Review</h2><nav class="tabs"><b>Overview</b><b>Course requirements</b><b>Teacher mappings</b><b>공동수업 설정</b><b>Constraints</b></nav><p>공동수업 후보: ${data.diagnostics.sharedSuggestions?.length ?? 0}, 풀타임 교사: ${data.diagnostics.fullTimeTeacherIds?.map(id => nameOf(id, 'teacher')).join(', ') || '없음'}, 역할 매핑 필요: ${data.diagnostics.teacherRoles?.join(', ') || '없음'}</p></section>${diagnostics()}${teacherMappings()}${requirementsPreview()}${ruleReview()}${constraintEditor()}<section class="panel"><h2>시간표 생성</h2>${blocking ? `<p class="error">남은 blocker: ${blockers.map(b => `[${b.code}] ${b.message}`).slice(0, 5).join(' / ')}</p>` : ''}<label>최대 초 <input id="sec" type="number" value="5"></label><label>최대 노드 <input id="nodes" type="number" value="20000"></label><label>Seed <input id="seed" type="number" value="42"></label><button id="solve" ${data.requirements.length === 0 || blocking ? 'disabled' : ''}>시간표 생성</button><button id="save">프로젝트 저장</button><button id="xlsx">Excel 내보내기</button><button id="pdf">PDF/인쇄</button></section>` : ''}${result && data ? `<section class="panel"><h2>진행/결과</h2><p>노드 ${result.progress.nodes}, 백트래킹 ${result.progress.backtracks}, 배정 ${result.progress.assigned}/${result.progress.total}, 미배정 ${result.progress.unassigned}, 점수 ${result.score}, 종료 ${result.progress.reason}</p><h3>학년별 시간표</h3>${data.grades.map(g => `<details open><summary>${g.name}</summary>${tableFor(a => a.gradeIds.includes(g.id), a => `${nameOf(a.subjectId, 'subject')}<br><small>${a.teacherIds.map(t => nameOf(t, 'teacher')).join(', ')}</small>`)}</details>`).join('')}<h3>교사별 시간표</h3><h3>공동수업</h3>${tableFor(a => a.gradeIds.length > 1, a => `${nameOf(a.subjectId, 'subject')}<br><small>${a.cohortIds.map(c => nameOf(c, 'cohort')).join(', ')}</small>`)}<h3>전체 수업</h3>${tableFor(() => true, a => `${nameOf(a.subjectId, 'subject')}<br><small>${a.teacherIds.map(t => nameOf(t, 'teacher')).join(', ') || '교사 없음/온라인'}</small>`)}<h3>검증 결과</h3>${[...validateResult(data, result), ...result.issues].map(i => `<p class="${i.level}">${i.message}</p>`).join('')}<h3>통계</h3><p>배정 교시 ${result.assignments.reduce((a, b) => a + b.length, 0)}, 미배정 교시 ${result.unassigned.reduce((a, b) => a + b.length, 0)}</p><h3>교사별 시간표</h3>${data.teachers.map(t => `<details><summary>${t.name}</summary>${tableFor(a => a.teacherIds.includes(t.id), a => `${nameOf(a.subjectId, 'subject')}<br><small>${a.cohortIds.map(c => nameOf(c, 'cohort')).join(', ')}</small>`)}</details>`).join('')}<h3>미배정/진단</h3>${result.issues.map(i => `<p class="error">${i.message}</p>`).join('')}</section>` : ''}</main>`; bind(); }
function bind() { document.querySelector('#file')?.addEventListener('change', async (e) => { const f = e.target.files?.[0]; if (!f)
    return; try {
    data = normalizeWorkbook(await parseWorkbookFile(f));
    result = null;
    render();
}
catch (err) {
    alert(err instanceof Error ? err.message : String(err));
} }); document.querySelectorAll('.map-home').forEach(el => el.addEventListener('change', () => { if (!data)
    return; data.roleMappings ??= { homeroomByGrade: {}, studentCouncil: null }; data.roleMappings.homeroomByGrade[el.dataset.grade] = el.value; data.requirements.forEach(r => { if (r.teacherRule?.type === 'role' && r.teacherRule.roleId === 'homeroom')
    r.status = 'ready'; }); render(); })); document.querySelector('#map-council')?.addEventListener('change', e => { if (!data)
    return; data.roleMappings ??= { homeroomByGrade: {}, studentCouncil: null }; data.roleMappings.studentCouncil = e.target.value || null; data.requirements.forEach(r => { if (r.teacherRule?.type === 'role' && r.teacherRule.roleId === 'student-council')
    r.status = 'ready'; }); render(); }); document.querySelector('#solve')?.addEventListener('click', () => { if (!data || data.requirements.length === 0)
    return; result = solveSchedule(data, { maxSeconds: Number(document.querySelector('#sec').value), maxNodes: Number(document.querySelector('#nodes').value), seed: Number(document.querySelector('#seed').value), allowUnassigned: true, weights: { unassigned: 10000 } }); result.issues.push(...validateResult(data, result)); render(); }); document.querySelector('#save')?.addEventListener('click', () => data && saveProject(data, result ?? undefined)); document.querySelector('#load')?.addEventListener('click', () => { const p = loadProject(); if (p) {
    data = p.data;
    result = p.result ?? null;
    render();
} }); document.querySelector('#xlsx')?.addEventListener('click', () => data && result && exportExcel(data, result)); document.querySelector('#pdf')?.addEventListener('click', printPdf); const add = (type) => { if (!data)
    return; const id = document.querySelector('#cr')?.value; if (!id)
    return; const slot = `${document.querySelector('#day').value}-${document.querySelector('#period').value}`; data.constraints.push({ id: `con_${Date.now()}`, type, targetIds: [id], value: type === 'after-school-only' ? 8 : slot, hard: true, source: 'manual' }); const r = data.requirements.find(x => x.id === id); if (r) {
    if (type === 'fixed-slot')
        r.fixedSlots = [slot];
    if (type === 'allowed-slots')
        r.allowedSlots.push(slot);
    if (type === 'forbidden-slots')
        r.forbiddenSlots.push(slot);
    if (type === 'after-school-only')
        r.afterSchool = true;
} render(); }; document.querySelector('#fix')?.addEventListener('click', () => add('fixed-slot')); document.querySelector('#after')?.addEventListener('click', () => add('after-school-only')); document.querySelector('#allow')?.addEventListener('click', () => add('allowed-slots')); document.querySelector('#forbid')?.addEventListener('click', () => add('forbidden-slots')); document.querySelector('#lock')?.addEventListener('click', () => add('locked-assignment')); }
render();
